CANON = ["intake", "er", "relation_graph", "features", "model_score", "queue"]

def decide(record: dict):
    if "stages" not in record:
        return ("REQUEST_STAGE_LIST", 0)
    if record.get("er_claims_parentesco"):
        return ("REJECT_ER_SCOPE", 0)
    if record.get("stages") != CANON:
        return ("REJECT_STAGE_ORDER", 0)
    if record.get("label_space") != "needs_review" or record.get("auto_fraud"):
        return ("REJECT_STAGE_ORDER", 0)
    return ("CONTINUE", len(CANON))

