def decide(reg: dict):
    for name, art in reg.items():
        if not art.get("owner"):
            return "ESCALATE_NO_OWNER", len(reg)
        if art.get("breaking") and art.get("bump") != "major":
            return "REJECT_BUMP_POLICY", len(reg)
    return "CONTINUE", len(reg)

