def assess(record: dict) -> str:
    if record.get("appeal"):
        if not record.get("second_reviewer"):
            return "MISSING:second_reviewer"
        return "reopen"
    auto = "queue" if record["score"] >= record["threshold"] else "skip"
    if record.get("human_action") is not None:
        return "PASS"  # override path validated externally
    return "PASS" if auto == "queue" else "PASS"

base = {"case_id": "CASO-LIM-039-T2B", "score": 0.9, "threshold": 0.7}
# Instruction: auto queue without human -> PASS with final queue; override skip -> PASS; appeal without second_reviewer -> MISSING
def assess2(record: dict) -> str:
    if record.get("appeal"):
        if not record.get("second_reviewer"):
            return "MISSING:second_reviewer"
        return "PASS"
    auto = "queue" if record["score"] >= record["threshold"] else "skip"
    if record.get("human_action") is not None:
        return "PASS"
    return "PASS"

print(assess2(base), assess2({**base, "human_action": "skip"}), assess2({**base, "appeal": True}))

def decide(event: dict):
    if event.get("override") and not event.get("audit_entry"):
        return "REJECT_NO_AUDIT", False
    if event.get("feedback"):
        if not event.get("leakage_care"):
            return "REJECT_LEAKAGE_CARE", False
        return "LOGGED", True
    return "LOGGED", True

