def decide(ops: dict):
    if ops.get("incident"):
        if not ops.get("prev_model_id"):
            return "REQUEST_PREV_MODEL", None
        return "ROLLBACK", ops["prev_model_id"]
    if ops.get("drift_high"):
        return "ABSTAIN", "current"
    return "STAY", "current_model"

