def decide(pm: dict):
    if pm.get("blameless") is not True:
        return "REJECT_BLAMEFUL", False
    if not pm.get("root_cause"):
        return "REQUEST_ROOT_CAUSE", False
    if not pm.get("actions"):
        return "REQUEST_ACTIONS", False
    return "CONTINUE", True

